={{
  (() => {
    let existingFotos = {};
    try {
      // Tenta converter o campo `fotos` existente em um objeto JSON
      existingFotos = $json.fotos ? JSON.parse($json.fotos) : {};
    } catch (e) {
      // Se der erro, assume que o campo estava vazio ou mal formatado
      existingFotos = {};
    }
    // Gera a nova chave para a imagem
    const newKey = `imagem${Object.keys(existingFotos).length + 1}`;
    // Adiciona a nova URL ao objeto JSON
    existingFotos[newKey] = $('Edit Fields9').item.json.publicUrl;
    // Retorna o objeto atualizado como uma string JSON
    return JSON.stringify(existingFotos);
  })()
}}

